import * as React from 'react';
import { MultiSelect } from '@tale-ui/react/multi-select';

const frameworks = [
  { id: 'react', name: 'React' },
  { id: 'vue', name: 'Vue' },
  { id: 'angular', name: 'Angular' },
  { id: 'svelte', name: 'Svelte' },
  { id: 'solid', name: 'SolidJS' },
];

export function FrameworkMultiSelect() {
  const [selected, setSelected] = React.useState(new Set<string>());

  return (
    <MultiSelect.Root
      label="Frameworks"
      placeholder="Select frameworks"
      description="Choose all that apply."
      items={frameworks}
      selectedKeys={selected}
      onSelectionChange={(keys) => setSelected(keys as Set<string>)}
      onReset={() => setSelected(new Set())}
      onSelectAll={() => setSelected(new Set(frameworks.map((f) => f.id)))}
    >
      {(item) => (
        <MultiSelect.Item id={item.id} textValue={item.name}>
          {item.name}
        </MultiSelect.Item>
      )}
    </MultiSelect.Root>
  );
}
